-- Part 2 RLS and security indexes
BEGIN;
CREATE OR REPLACE FUNCTION rq.current_company_id() RETURNS uuid LANGUAGE sql STABLE AS $$ SELECT nullif(current_setting('rq.company_id',true),'')::uuid $$;
DO $$ DECLARE t text; BEGIN
  FOREACH t IN ARRAY ARRAY['procurement_requests','procurement_request_lines','sourcing_events','approval_cases','approval_steps','purchase_orders','purchase_order_lines','goods_receipts','procurement_policies','rfqs','rfq_versions','rfq_requirements','rfq_visibility_rules','supplier_invitations','clarifications','clarification_answers','quotations','quotation_versions','quotation_lines','quote_comparisons','award_decisions','supplier_relationships','supplier_segments','supplier_qualifications','supplier_scorecards','performance_periods','supplier_risks','supplier_reviews','corrective_action_plans','preferred_vendor_lists','crm_accounts','crm_contacts','crm_contact_points','crm_opportunities','crm_pipeline_stages','crm_activities','crm_tasks','crm_campaign_members','crm_consents','crm_attributions','assets','asset_identifiers','asset_locations','asset_configurations','asset_components','asset_documents','asset_relationships','asset_service_records','asset_meter_readings','asset_tags','lifecycle_plans','lifecycle_stages','asset_acquisitions','installation_records','commissioning_records','upgrade_programs','refurbishment_records','replacement_assessments','disposal_records','lifecycle_costs','digital_passports','passport_sections','passport_claims','passport_credentials','passport_disclosures','passport_shares','passport_qr_codes','passport_nfc_tokens','passport_verifications','digital_twins','twin_models','twin_model_versions','twin_nodes','twin_edges','twin_properties','twin_state_snapshots','twin_simulations','twin_alert_rules','maintenance_models','model_versions','feature_definitions','prediction_runs','maintenance_predictions','prediction_explanations','maintenance_recommendations','recommendation_reviews','model_monitoring','failure_labels','manufacturers','product_families','equipment_models','model_configurations','manufacturing_sites','production_capacities','manufacturer_channels','warranty_programs','technical_bulletins','oem_relationships','distributors','distribution_authorisations','territories','brand_portfolios','inventory_positions','availability_promises','price_books','channel_orders','warranty_routes','channel_performance','contractor_organisations','technicians','technician_credentials','contractor_availability','service_territories','job_dispatches','field_checkins','service_reports','labour_rates','contractor_equipment','service_providers','service_catalogues','service_offerings','service_level_agreements','service_coverage','service_requests','service_deliveries','service_evidence','service_subscriptions','consultants','expertise_profiles','consultant_credentials','consulting_engagements','engagement_scopes','conflict_declarations','consulting_deliverables','timesheets','professional_references','job_postings','job_requirements','candidate_profiles','candidate_credentials','candidate_consents','job_applications','application_stages','interview_schedules','employment_offers','workforce_providers','finance_providers','finance_products','finance_eligibility_rules','finance_referrals','finance_applications','finance_documents','indicative_terms','finance_decisions','finance_commissions','insurance_providers','insurance_products','risk_profiles','insurance_referrals','insurance_submissions','insurance_quotes','policy_records','coverage_evidence','claims_referrals','insurance_commissions','freight_requests','freight_items','freight_lanes','carriers','carrier_capabilities','freight_quotes','shipments','shipment_milestones','tracking_events','proofs_of_delivery','freight_exceptions','warehouse_providers','warehouse_facilities','storage_zones','capacity_positions','storage_requirements','warehouse_quotes','storage_agreements','inventory_custody','warehouse_movements','fulfilment_orders','warehouse_evidence','advertisers','advertising_accounts','campaigns','ad_groups','ad_creatives','targeting_rules','ad_placements','ad_impressions','ad_clicks','ad_conversions','ad_budgets','quality_scores','community_profiles','follows','posts','post_versions','media_items','comments','reactions','communities','community_memberships','moderation_cases','content_reports','academy_providers','courses','course_versions','learning_modules','enrolments','learning_progress','assessments','assessment_attempts','credentials','credential_verifications','cpd_records','event_organisers','events','event_sessions','venues','event_exhibitors','event_sponsors','event_registrations','event_tickets','attendance_records','event_leads','event_feedback'] LOOP
    EXECUTE format('ALTER TABLE rq.%I ENABLE ROW LEVEL SECURITY',t);
    EXECUTE format('DROP POLICY IF EXISTS p_company_scope ON rq.%I',t);
    EXECUTE format('CREATE POLICY p_company_scope ON rq.%I USING (company_id = rq.current_company_id()) WITH CHECK (company_id = rq.current_company_id())',t);
  END LOOP;
END $$;
COMMIT;
